+    #[test]
+    fn test_pragma_quick_check_reports_lock_byte_page_reference() {
+        let conn = Connection::open_with_page_size(":memory:", 1024).unwrap();
+        conn.execute("CREATE TABLE t (id INTEGER PRIMARY KEY, payload TEXT);")
+            .unwrap();
+
+        let table_root_page = conn
+            .schema
+            .borrow()
+            .iter()
+            .find(|table| table.name.eq_ignore_ascii_case("t"))
+            .map(|table| PageNumber::new(u32::try_from(table.root_page).unwrap()).unwrap())
+            .expect("test table root page");
+
+        let payload = "z".repeat(900);
+        let root_is_interior = || {
+            let cx = Cx::new();
+            if conn.retained_autocommit_txn.borrow().is_some() {
+                conn.flush_retained_autocommit_txn(&cx).unwrap();
+            }
+            conn.invalidate_cached_write_txn(&cx);
+            conn.invalidate_cached_read_snapshot(&cx);
+            let mut txn = conn.pager.begin(&cx, TransactionMode::ReadOnly).unwrap();
+            let page = txn.get_page(&cx, table_root_page).unwrap();
+            let header = fsqlite_btree::BtreePageHeader::parse(
+                page.as_ref(),
+                fsqlite_btree::header_offset_for_page(table_root_page),
+            )
+            .unwrap();
+            txn.rollback(&cx).unwrap();
+            header.page_type == fsqlite_btree::BtreePageType::InteriorTable
+        };
+
+        for rowid in 1..=64 {
+            conn.execute(&format!(
+                "INSERT INTO t VALUES ({rowid}, '{}');",
+                payload
+            ))
+            .unwrap();
+            if root_is_interior() {
+                break;
+            }
+            assert!(
+                rowid < 64,
+                "table root did not split under sustained inserts"
+            );
+        }
+
+        let lock_page = PageNumber::new(fsqlite_pager::lock_byte_page(conn.pager.page_size()))
+            .expect("lock-byte page number");
+        let cx = Cx::new();
+        if conn.retained_autocommit_txn.borrow().is_some() {
+            conn.flush_retained_autocommit_txn(&cx).unwrap();
+        }
+        conn.invalidate_cached_write_txn(&cx);
+        conn.invalidate_cached_read_snapshot(&cx);
+
+        let mut txn = conn.pager.begin(&cx, TransactionMode::Immediate).unwrap();
+        let mut root_page = txn.get_page(&cx, table_root_page).unwrap().into_vec();
+        let header_offset = fsqlite_btree::header_offset_for_page(table_root_page);
+        let root_header = fsqlite_btree::BtreePageHeader::parse(&root_page, header_offset).unwrap();
+        assert_eq!(
+            root_header.page_type,
+            fsqlite_btree::BtreePageType::InteriorTable,
+            "test setup requires an interior table root"
+        );
+        root_page[header_offset + 8..header_offset + 12]
+            .copy_from_slice(&lock_page.get().to_be_bytes());
+        let lock_page_bytes = vec![0_u8; usize::try_from(conn.pager.page_size().get()).unwrap()];
+        txn.write_page(&cx, lock_page, &lock_page_bytes).unwrap();
+        txn.write_page(&cx, table_root_page, &root_page).unwrap();
+        txn.commit(&cx).unwrap();
+
+        conn.invalidate_cached_write_txn(&cx);
+        conn.invalidate_cached_read_snapshot(&cx);
+        let rows = conn.query("PRAGMA quick_check;").unwrap();
+        assert_eq!(rows.len(), 1);
+        let SqliteValue::Text(message) = &rows[0].values()[0] else {
+            panic!("quick_check should return a text diagnostic row");
+        };
+        assert!(
+            message.contains("reserved lock-byte page"),
+            "unexpected quick_check diagnostic: {message}"
+        );
+    }
